2	 * База API с префиксом версии (например `https://host/api/v1`).
3	 * Семантика как в edu-app: абсолютный URL или путь относительно `window.location.origin`.
4	 * VITE_API_BASE_URL уже содержит `/api/v1` — НЕ добавляем префикс повторно.
5	 */
6	export function getApiBase(): string {
7	  const raw = (import.meta.env.VITE_API_BASE_URL ?? import.meta.env.VITE_API_URL ?? "").trim().replace(/\/$/, "");
8	  if (!raw) return "";
9	  if (raw.startsWith("http://") || raw.startsWith("https://")) return raw;
10	  const prefix = raw.startsWith("/") ? raw : `/${raw}`;
11	  return `${window.location.origin}${prefix}`;
12	}
