3	import type { BaseQueryFn, FetchArgs, FetchBaseQueryError } from "@reduxjs/toolkit/query";
4	import { fetchBaseQuery } from "@reduxjs/toolkit/query/react";
5	
6	const isErrorStatus = (result: { error?: FetchBaseQueryError }, status: number): boolean =>
7	  result.error?.status === status;
8	
9	export function createBaseQuery<TRootState = unknown>(
10	  config: BaseQueryConfig<TRootState>,
11	): BaseQueryFn<string | FetchArgs, unknown, FetchBaseQueryError, BaseQueryExtraOptions> {
12	  return async (args, api, extraOptions) => {
13	    const rawBaseQuery = fetchBaseQuery({
14	      baseUrl: config.baseUrl,
15	      credentials: config.credentials,
16	      prepareHeaders: (headers, { getState }) => {
17	        const token = config.getToken?.(getState() as TRootState);
18	        if (token) {
19	          headers.set("Authorization", `Bearer ${token}`);
20	        }
21	        return headers;
22	      },
23	    });
24	
25	    const result = await rawBaseQuery(args, api, extraOptions);
26	    const isUnauthorized = isErrorStatus(result, 401);
27	    const skipRedirect = extraOptions?.skipAuthRedirect ?? config.skipAuthRedirect?.(args);
28	
29	    if (isUnauthorized && !skipRedirect) {
30	      config.onUnauthorized?.();
31	    }
32	
33	    return result;
34	  };
35	}
