10	type StorePreloadedState<S> = ConfigureStoreOptions<S>["preloadedState"];
11	
12	export interface CreateStoreConfig<TRootState = unknown> {
13	  baseUrl: string;
14	  credentials?: RequestCredentials;
15	  getToken?: (state: TRootState) => string | null;
16	  onUnauthorized?: () => void;
17	  skipAuthRedirect?: (args: string | FetchArgs) => boolean;
18	  tagTypes: readonly string[];
19	  reducerPath?: string;
20	  staticReducers: ReducersMapObject;
21	  preloadedState?: StorePreloadedState<TRootState>;
22	  extraMiddleware?: Middleware[];
23	}
24	
25	export function createStore<TRootState extends object>(config: CreateStoreConfig<TRootState>) {
26	  let storeRef: ReturnType<typeof configureStore> | null = null;
27	
28	  const baseQuery = createBaseQuery<TRootState>({
29	    baseUrl: config.baseUrl,
30	    credentials: config.credentials,
31	    getToken: config.getToken,
32	    onUnauthorized: () => {
33	      if (storeRef) config.onUnauthorized?.();
34	    },
35	    skipAuthRedirect: config.skipAuthRedirect,
36	  });
37	
38	  const baseApi = createBaseApi(baseQuery, {
39	    reducerPath: config.reducerPath ?? "api",
40	    tagTypes: config.tagTypes,
41	  });
42	
43	  const staticReducers: ReducersMapObject = {
44	    [baseApi.reducerPath]: baseApi.reducer,
45	    ...config.staticReducers,
46	  };
47	
48	  const reducerManager = createReducerManager(staticReducers);
49	
50	  const store = configureStore({
51	    reducer: ((state, action) => reducerManager.reduce(state, action)) as Reducer<TRootState>,
52	    preloadedState: config.preloadedState,
53	    middleware: getDefaultMiddleware =>
54	      getDefaultMiddleware()
55	        .concat(baseApi.middleware)
56	        .concat(config.extraMiddleware ?? []),
57	  });
58	
59	  storeRef = store;
60	
61	  const storeWithInjection = Object.assign(store, {
62	    injectReducer(key: string, reducer: Reducer) {
63	      reducerManager.inject(key, reducer);
64	      store.replaceReducer(((state, action) => reducerManager.reduce(state, action)) as Reducer<TRootState>);
65	    },
66	  });
67	
68	  return { store: storeWithInjection, baseApi };
69	}
70	
71	export type AppStore = ReturnType<typeof createStore>["store"];
