145	export function KtpPanel({ subjectId }: { subjectId: string }) {
146	  const { data: catalog, isLoading } = useGetKtpCatalogQuery(subjectId, { skip: !subjectId });
147	  const [addTopic] = useAddKtpTopicMutation();
148	  const [updateTopic] = useUpdateKtpTopicMutation();
149	  const [deleteTopic] = useDeleteKtpTopicMutation();
150	  const [reorderTopics] = useReorderKtpTopicsMutation();
151	  const [importTopics] = useImportKtpTopicsMutation();
152	
153	  const [newTitle, setNewTitle] = useState("");
154	  const [importText, setImportText] = useState("");
155	  const [importReplace, setImportReplace] = useState(false);
156	  const [error, setError] = useState<string | null>(null);
157	  const [busy, setBusy] = useState(false);
158	  const [confirmReplace, setConfirmReplace] = useState<KtpTopicInput[] | null>(null);
159	
160	  const topics = useMemo(
161	    () => (catalog ? [...catalog.topics].sort((a, b) => a.order - b.order) : []),
162	    [catalog],
163	  );
164	
165	  const run = async (fn: () => Promise<unknown>) => {
166	    setError(null);
167	    setBusy(true);
168	    try {
169	      await fn();
170	    } catch {
171	      setError("Не удалось выполнить операцию. Попробуйте ещё раз.");
172	    } finally {
173	      setBusy(false);
174	    }
175	  };
176	
177	  const handleAdd = () => {
178	    const title = newTitle.trim();
179	    if (!title) return;
180	    void run(async () => {
181	      await addTopic({ subjectId, body: { title } }).unwrap();
182	      setNewTitle("");
183	    });
184	  };
185	
186	  const move = (index: number, dir: -1 | 1) => {
187	    const target = index + dir;
188	    if (target < 0 || target >= topics.length) return;
189	    const reordered = [...topics];
190	    const a = reordered[index];
191	    const b = reordered[target];
192	    if (!a || !b) return;
193	    reordered[index] = b;
194	    reordered[target] = a;
195	    void run(() => reorderTopics({ subjectId, orderedTopicIds: reordered.map(t => t._id) }).unwrap());
196	  };
197	
198	  const parseImport = (): KtpTopicInput[] | null => {
199	    if (!importText.trim()) return null;
200	    let parsed: unknown;
201	    try {
202	      parsed = JSON.parse(importText);
203	    } catch {
204	      setError("Невалидный JSON");
205	      return null;
206	    }
207	    const raw = Array.isArray(parsed) ? parsed : (parsed as { topics?: unknown }).topics;
208	    if (!Array.isArray(raw)) {
209	      setError('Ожидается массив тем или объект { "topics": [...] }');
210	      return null;
211	    }
212	    return raw as KtpTopicInput[];
213	  };
214	
215	  const doImport = (list: KtpTopicInput[]) =>
216	    run(async () => {
217	      await importTopics({ subjectId, topics: list, replace: importReplace }).unwrap();
218	      setImportText("");
219	    });
220	
221	  const handleImport = () => {
222	    setError(null);
223	    const list = parseImport();
224	    if (!list) return;
225	    // Замена существующих — разрушительна, подтверждаем.
226	    if (importReplace) {
227	      setConfirmReplace(list);
228	      return;
229	    }
230	    doImport(list);
231	  };
232	
233	  return (
234	    <Box>
235	      <Typography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
236	        Канонический упорядоченный список тем предмета. Карта знаний строится из КТП: темы книг (разных
237	        классов) привязываются к этим темам.
238	      </Typography>
239	
240	      {error && (
241	        <Alert severity="error" sx={{ mb: 2 }} onClose={() => setError(null)}>
242	          {error}
243	        </Alert>
244	      )}
245	
246	      <Typography variant="subtitle1" fontWeight={600} sx={{ mb: 1 }}>
247	        Темы КТП ({topics.length})
248	      </Typography>
249	
250	      {isLoading && <CircularProgress size={20} sx={{ my: 1 }} />}
251	      {!isLoading && topics.length === 0 && (
252	        <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
253	          Тем пока нет. Добавьте вручную или импортируйте JSON ниже.
254	        </Typography>
255	      )}
256	
257	      <Stack spacing={1} sx={{ mb: 2 }}>
258	        {topics.map((topic, index) => (
259	          <KtpTopicRow
260	            key={topic._id}
261	            topic={topic}
262	            index={index}
263	            total={topics.length}
264	            onMove={move}
265	            onSave={body => void run(() => updateTopic({ subjectId, topicId: topic._id, body }).unwrap())}
266	            onDelete={() => run(() => deleteTopic({ subjectId, topicId: topic._id }).unwrap())}
267	          />
268	        ))}
269	      </Stack>
270	
271	      <Stack direction="row" spacing={1} sx={{ mb: 4 }}>
272	        <TextField
273	          size="small"
274	          fullWidth
275	          label="Новая тема КТП"
276	          value={newTitle}
277	          onChange={e => setNewTitle(e.target.value)}
278	          onKeyDown={e => {
279	            if (e.key === "Enter") handleAdd();
280	          }}
281	        />
282	        <AsyncButton variant="contained" loading={busy} onClick={handleAdd}>
283	          Добавить
284	        </AsyncButton>
285	      </Stack>
286	
287	      <Divider sx={{ mb: 3 }} />
288	
289	      <Typography variant="subtitle1" fontWeight={600} sx={{ mb: 1 }}>
290	        Массовый импорт (JSON)
291	      </Typography>
292	      <Typography variant="caption" color="text.secondary" component="p" sx={{ mb: 1 }}>
293	        Формат: массив объектов {"{ title, code?, description?, order? }"} или {'{ "topics": [...] }'}.
294	      </Typography>
295	      <TextField
296	        multiline
297	        minRows={4}
298	        fullWidth
299	        value={importText}
300	        onChange={e => setImportText(e.target.value)}
301	        placeholder='[{ "title": "Клетка", "code": "1.1" }, { "title": "Митохондрии" }]'
302	        sx={{ mb: 1 }}
303	      />
304	      <Stack direction="row" spacing={2} alignItems="center">
305	        <FormControlLabel
306	          control={<Checkbox checked={importReplace} onChange={e => setImportReplace(e.target.checked)} />}
307	          label="Заменить существующие"
308	        />
309	        <AsyncButton variant="outlined" loading={busy} onClick={handleImport}>
310	          Импортировать
311	        </AsyncButton>
312	      </Stack>
313	
314	      <ConfirmDialog
315	        open={confirmReplace !== null}
316	        title="Заменить существующие темы?"
317	        body={`Текущие ${topics.length} тем КТП будут заменены импортируемыми (${confirmReplace?.length ?? 0}). Это действие необратимо.`}
318	        confirmLabel="Заменить"
319	        confirmColor="error"
320	        loading={busy}
321	        onConfirm={async () => {
322	          if (confirmReplace) await doImport(confirmReplace);
323	          setConfirmReplace(null);
324	        }}
325	        onClose={() => setConfirmReplace(null)}
326	      />
327	    </Box>
328	  );
329	}
